1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given empty grid", () => {
6	    const livingCells = new Set<string>();
7	    const result = nextGeneration(livingCells);
8	    expect(result).toEqual(new Set<string>());
9	  });
10	  it("should kill a single cell with no neighbors (underpopulation)", () => {
11	    const livingCells = new Set<string>(["0,0"]);
12	    const result = nextGeneration(livingCells);
13	    expect(result).toEqual(new Set<string>());
14	  });
15	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
16	    const livingCells = new Set<string>(["0,0", "1,0"]);
17	    const result = nextGeneration(livingCells);
18	    expect(result).toEqual(new Set<string>());
19	  });
20	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
21	    const livingCells = new Set<string>(["0,0", "1,0", "0,1"]);
22	    const result = nextGeneration(livingCells);
23	    expect(result).toEqual(new Set<string>(["0,0", "1,0", "0,1", "1,1"]));
24	  });
25	  it("should keep a live cell alive when it has exactly 2 live neighbors (survival)", () => {
26	    const livingCells = new Set<string>(["0,0", "1,0", "2,0"]);
27	    const result = nextGeneration(livingCells);
28	    expect(result.has("1,0")).toBe(true);
29	  });
30	  it("should keep a live cell alive when it has exactly 3 live neighbors (survival)", () => {
31	    const livingCells = new Set<string>(["0,0", "1,0", "2,0", "1,1"]);
32	    const result = nextGeneration(livingCells);
33	    expect(result.has("1,0")).toBe(true);
34	  });
35	  it("should preserve a block still life where each cell has exactly 3 neighbors", () => {
36	    const livingCells = new Set<string>(["0,0", "1,0", "0,1", "1,1"]);
37	    const result = nextGeneration(livingCells);
38	    expect(result).toEqual(new Set<string>(["0,0", "1,0", "0,1", "1,1"]));
39	  });
40	  it.todo("should kill a live cell with 4 or more live neighbors (overpopulation)");
41	  it.todo("should evolve a blinker from vertical to horizontal orientation");
42	});
