1	export function nextGeneration(livingCells: Set<string>): Set<string> {
2	  const neighborCounts = new Map<string, number>();
3	
4	  for (const cell of livingCells) {
5	    const [x, y] = cell.split(",").map(Number);
6	    for (let dx = -1; dx <= 1; dx++) {
7	      for (let dy = -1; dy <= 1; dy++) {
8	        if (dx === 0 && dy === 0) continue;
9	        const key = `${x + dx},${y + dy}`;
10	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
11	      }
12	    }
13	  }
14	
15	  const result = new Set<string>();
16	  for (const [cell, count] of neighborCounts) {
17	    if (count === 3 || (count === 2 && livingCells.has(cell))) {
18	      result.add(cell);
19	    }
20	  }
21	
22	  return result;
23	}
